import javax.jws.WebMethod;
import javax.jws.WebService;
import javax.xml.ws.Endpoint;
import javax.xml.ws.handler.MessageContext;
import javax.xml.ws.WebServiceContext;
import javax.annotation.Resource;
import javax.xml.ws.handler.soap.SOAPMessageContext;
import javax.xml.soap.SOAPBody;
import javax.xml.soap.SOAPElement;
import javax.xml.soap.SOAPException;
import javax.xml.soap.SOAPMessage;
import java.util.Iterator;
import java.util.List;
import java.util.ArrayList;

@WebService
public class OrderProcessingService {

    @Resource
    private WebServiceContext wsContext;

    @WebMethod
    public String processOrder() {
        SOAPMessageContext messageContext = (SOAPMessageContext) wsContext.getMessageContext();
        SOAPMessage soapMessage = messageContext.getMessage();
        List<OrderItem> orderItems = new ArrayList<>();
        double totalPrice = 0.0;

        try {
            SOAPBody soapBody = soapMessage.getSOAPBody();
            Iterator<?> iterator = soapBody.getChildElements();

            while (iterator.hasNext()) {
                Object next = iterator.next();
                if (next instanceof SOAPElement) {
                    SOAPElement element = (SOAPElement) next;
                    if ("OrderItem".equals(element.getLocalName())) {
                        String itemName = element.getAttribute("name");
                        double itemPrice = Double.parseDouble(element.getAttribute("price"));
                        int quantity = Integer.parseInt(element.getAttribute("quantity"));

                        // Validate input
                        if (itemPrice < 0 || quantity < 0) {
                            return "Invalid order item details.";
                        }

                        OrderItem orderItem = new OrderItem(itemName, itemPrice, quantity);
                        orderItems.add(orderItem);
                        totalPrice += itemPrice * quantity;
                    }
                }
            }
        } catch (SOAPException | NumberFormatException e) {
            return "Error processing order: " + e.getMessage();
        }

        // Process order securely
        if (orderItems.isEmpty()) {
            return "No valid order items found.";
        }

        // Here you would typically save the order to a database securely
        // Ensure sensitive data is not logged or stored in plaintext

        return "Order processed successfully. Total Price: $" + totalPrice;
    }

    public static void main(String[] args) {
        Endpoint.publish("http://localhost:8080/OrderProcessingService", new OrderProcessingService());
    }

    private static class OrderItem {
        private String name;
        private double price;
        private int quantity;

        public OrderItem(String name, double price, int quantity) {
            this.name = name;
            this.price = price;
            this.quantity = quantity;
        }
    }
}